// 挑最久沒重發的一筆；沒有就整條線靜靜結束（不推 LINE）
const rows = $input.first().json.results || [];
if (!rows.length) return [];
const p = rows[0].properties || {};
const txt = k => (p[k]?.rich_text?.[0]?.plain_text || '');
const permalink = p['粉專貼文連結']?.url || '';
// permalink 形如 https://www.facebook.com/{pageId}/posts/{postId} → FB 刪文要 {pageId}_{postId}
let oldPostId = '';
let m = permalink.match(/facebook\.com\/(\d+)\/posts\/(\w+)/);
if (m) { oldPostId = `${m[1]}_${m[2]}`; }
else { m = permalink.match(/facebook\.com\/(\d+_\w+)/); if (m) oldPostId = m[1]; }
return [{ json: {
  notionPageId: rows[0].id,
  contract_no: txt('案件編號').toUpperCase(),
  keisId: p['KEIS物件ID']?.number || null,
  oldPermalink: permalink,
  oldPostId,
  重發次數: p['重發次數']?.number || 0,
  文案版本: p['文案版本']?.number || 1,
  official_url: p['來源連結']?.url || '',
} }];

// 白名單清洗：只留廣告欄位，屋主個資一律 drop
// 2026-07-23 KEIS 砍欄位後改版：official_url 改從列表帶、格局樓層自己組、屋齡學區交給永慶官網
const d = $input.first().json.data || $input.first().json;
const list = $('挑一件重發').first().json || {};
const s = v => (v === null || v === undefined) ? '' : String(v).trim();
const num = v => (v === null || v === undefined || v === '') ? null : Number(v);
const r1 = v => (v === null || v === undefined || v === '') ? null : Math.round(Number(v) * 10) / 10;

const type = s(d.property_type);
const isLand = /土地|農|廠|車位/.test(type);

// 格局：只寫有數字的，全 0 或土地類就留白（KEIS 前端也是這樣顯示）
const parts = [[Number(d.room_count) || 0, '房'], [Number(d.living_count) || 0, '廳'], [Number(d.bathroom_count) || 0, '衛']];
const 格局 = isLand ? '' : parts.filter(p => p[0] > 0).map(p => p[0] + p[1]).join('');

// 樓層：起訖不同寫成範圍、地下室寫 B1、缺任一個就留白
const f = n => (n === null || n === undefined || n === '') ? null : (Number(n) < 0 ? 'B' + Math.abs(Number(n)) : String(Number(n)));
const a = f(d.floor_start), b = f(d.floor_end), t = f(d.total_floors);
let 樓層 = '';
if (!isLand && a && t) 樓層 = (b && b !== a ? a + '-' + b : a) + '/' + t;

const 賣點 = [d.feature_1, d.feature_2, d.feature_3, d.feature_4, d.feature_5].map(s).filter(Boolean);

return [{ json: {
  contract_no: s(d.contract_no).toUpperCase(),
  keisId: d.id,
  案名: s(d.case_name),
  總價萬: num(d.case_price),
  單價: num(d.unit_price),
  建物類型: type,
  格局,
  主建坪: r1(d.main_area),
  建物坪: r1(d.total_area),
  樓層,
  社區: s(d.community_name),
  地址: [s(d.property_address_city), s(d.property_address_district), s(d.property_address_road)].join(''),
  車位: [s(d.parking_type), s(d.parking_method)].filter(Boolean).join('/'),
  專員: s(d.sales_agent_name),
  門市: s(d.store_name),
  official_url: s(list.official_url),
  賣點,
  機能: { 商圈: s(d.market_info), 捷運: s(d.mrt_station), 公園: s(d.park_info) },
}}];

