// 永慶官網補資料：補回 KEIS 砍掉的屋齡/學區，並用官網公開版本交叉驗證格局與樓層
// 反查邏輯沿用線 D：搜尋頁 JSON-LD 拿候選 → 逐一開頁用標題驗證（第一個候選固定是假 id）
const norm = s => String(s || '').replace(/\s+/g, '').toLowerCase();
const UA = { 'user-agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/126 Safari/537.36', 'accept-language': 'zh-TW,zh;q=0.9' };
const results = [];

for (const item of $input.all()) {
  const src = item.json;
  const out = { ycUrl: '', ycHouseId: '', ycNote: '', 屋齡: null, 學區: '', 格局: src['格局'] || '', 樓層: src['樓層'] || '', 交叉檢查: [] };
  try {
    const digits = String(src.contract_no || '').replace(/^[A-Za-z]+/, '');
    const city = (String(src['地址'] || '').match(/^(.{1,3}?[縣市])/) || [])[1] || '高雄市';
    const listUrl = `https://buy.yungching.com.tw/list/${encodeURIComponent(city)}-_c/${digits}_kw`;
    const html = String(await this.helpers.httpRequest({ url: listUrl, json: false, timeout: 20000, headers: UA }));
    let cands = [];
    for (const m of html.matchAll(/<script type="application\/ld\+json">([\s\S]*?)<\/script>/g)) {
      let d; try { d = JSON.parse(m[1]); } catch (e) { continue; }
      if (d['@type'] === 'ItemList' && Array.isArray(d.itemListElement)) {
        cands = d.itemListElement.map(e => String(e.url || '')).filter(u => /\/house\/\d+/.test(u));
      }
    }
    const want = norm(src['案名']).split('|')[0].split('｜')[0];
    let page = '';
    for (const u of cands.slice(0, 4)) {
      const p = String(await this.helpers.httpRequest({ url: u, json: false, timeout: 20000, headers: UA }));
      const t = (p.match(/<title>([\s\S]*?)<\/title>/) || [])[1] || '';
      const head = norm(t.split('|')[0].split('｜')[0]);
      if (head && want && (head === want || head.startsWith(want) || want.startsWith(head))) {
        out.ycUrl = u; out.ycHouseId = (u.match(/\/house\/(\d+)/) || [])[1] || ''; page = p; break;
      }
    }
    if (!page) {
      out.ycNote = cands.length ? `候選 ${cands.length} 筆對不上標題` : '搜尋無候選';
    } else {
      const t = page.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');
      const age = (t.match(/屋齡\s*([0-9.]{1,5})\s*年/) || [])[1];
      if (age) out['屋齡'] = Math.round(Number(age));
      out['學區'] = [...new Set((t.match(/[一-龥]{2,6}(?:國小|國中)/g) || [])
        .map(s => s.replace(/^(近|鄰|臨|旁|到|往)/, '')))].filter(s => s.length >= 3).slice(0, 3).join('、');
      const ycLayout = (t.match(/([0-9]+房[0-9]+廳[0-9]+衛)/) || [])[1] || '';
      const ycFloor = ((t.match(/([0-9B]{1,3}\s*\/\s*[0-9]{1,3})\s*樓/) || [])[1] || '').replace(/\s+/g, '');
      // 交叉驗證：兩邊都有值但對不上 → 留白，寧可少講
      if (ycLayout && src['格局']) {
        if (norm(ycLayout) !== norm(src['格局'])) { out['格局'] = ''; out['交叉檢查'].push(`格局不一致(KEIS ${src['格局']} / 官網 ${ycLayout})`); }
      } else if (ycLayout && !src['格局']) { out['格局'] = ycLayout; }
      if (ycFloor && src['樓層']) {
        if (norm(ycFloor) !== norm(src['樓層'])) { out['樓層'] = ''; out['交叉檢查'].push(`樓層不一致(KEIS ${src['樓層']} / 官網 ${ycFloor})`); }
      } else if (ycFloor && !src['樓層']) { out['樓層'] = ycFloor; }
      out.ycNote = 'ok';
    }
  } catch (e) {
    out.ycNote = '查詢失敗：' + (e.message || e);
  }
  if (!out.ycUrl) out.ycUrl = src.official_url || '';
  results.push({ json: { ...src, ...out } });
}
return results;

// 數字守門員 v2：
// (1) 文案裡的每個數字都要在官方事實裡找得到
// (2) 官方沒有的欄位（屋齡/學區），文案裡連提都不准提——擋 AI 自己腦補
const j = $input.first().json;

const facts = new Set();
const push = v => {
  if (v === null || v === undefined || v === '') return;
  const n = String(v).replace(/,/g, '');
  facts.add(n);
  if (/^\d+\.\d+$/.test(n)) { facts.add(String(Math.round(Number(n)))); facts.add(n.split('.')[0]); }
  if (/^\d+$/.test(n)) facts.add(String(Number(n)));
};
[j['總價萬'], j['單價'], j['主建坪'], j['建物坪'], j['屋齡']].forEach(push);
const raw = [j['格局'], j['樓層'], j['地址'], j['案名'], j['社區'], j['車位'], j['學區'],
  ...(j['賣點'] || []), ...Object.values(j['機能'] || {})].join(' ');
(raw.match(/\d+(?:\.\d+)?/g) || []).forEach(push);
['0912877583', '11034791100', '417208', '111'].forEach(push);

const fb = String(j['粉專文案'] || '');
const grp = String(j['社團文案'] || '');
const body = fb + '\n' + grp;

// (1) 數字檢查（先把網址拿掉，LINE 連結的亂碼裡有數字，不是文案在講的數字）
const scan = body.replace(/https?:\/\/\S+/g, ' ');
const used = [...new Set((scan.match(/\d+(?:\.\d+)?/g) || []))];
const badNums = used.filter(n => !facts.has(n) && !facts.has(String(Number(n))));

// (2) 沒資料就不准提
const banned = [];
if (j['屋齡'] === null || j['屋齡'] === undefined || j['屋齡'] === '') {
  if (/屋齡|年新|新成屋|中古/.test(body)) banned.push('屋齡（官方沒這筆資料）');
}
if (!j['學區']) {
  if (/學區|國小|國中/.test(body)) banned.push('學區（官方沒這筆資料）');
}
if (!j['格局'] && /\d+房\d+廳/.test(body)) banned.push('格局（官方沒這筆資料）');
if (!j['樓層'] && /\d+\s*\/\s*\d+\s*樓|樓層/.test(body)) banned.push('樓層（官方沒這筆資料）');

const ctx = n => {
  const i = body.indexOf(n);
  return i < 0 ? '' : body.slice(Math.max(0, i - 12), i + 12).replace(/\n/g, ' ');
};
const ok = badNums.length === 0 && banned.length === 0;
const msg = ok ? '' :
  `⚠️ ${j.contract_no} 這篇沒發，文案沒過檢查：\n` +
  (badNums.length ? `・查無出處的數字：${badNums.map(n => `${n}（…${ctx(n)}…）`).join('；')}\n` : '') +
  (banned.length ? `・不該提的項目：${banned.join('、')}\n` : '') +
  `Notion 沒有建列，要發請手動處理。`;

return [{ json: { ...j, _guardOk: ok, _guardBad: badNums, _guardBanned: banned, _guardMsg: msg } }];

// 解壓後所有照片在同一筆的多個 binary 欄位裡，拆成一筆一張，最多 10 張（FB 單篇上限）
const item = $input.first();
const bin = item.binary || {};
const keys = Object.keys(bin).sort((a, b) => String(bin[a].fileName || a).localeCompare(String(bin[b].fileName || b), 'en', { numeric: true }));
const pick = keys.filter(k => /image\//.test(bin[k].mimeType || '')).slice(0, 10);
if (!pick.length) return [];
return pick.map((k, i) => ({ json: { idx: i, fileName: bin[k].fileName }, binary: { photo: bin[k] } }));
